import{_ as r,c as o,o as s,ag as n}from"./chunks/framework.XjE0kKti.js";const g="/gatewayweb/docs/assets/hub0060-tunnel-server-list.BGWXBLnt.png",a="/gatewayweb/docs/assets/hub0060-tunnel-server-context-menu.D2JyzuoB.png",e="/gatewayweb/docs/assets/hub0060-regist-client-list.DsKTOac6.png",d="/gatewayweb/docs/assets/hub0060-regist-service-list.CnEBbxWL.png",_=JSON.parse('{"title":"隧道服务器（hub0060）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0060.md","filePath":"modules/hub0060.md","lastUpdated":1776841524000}'),h={name:"modules/hub0060.md"};function l(i,t,b,u,c,p){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="隧道服务器-hub0060" tabindex="-1">隧道服务器（hub0060） <a class="header-anchor" href="#隧道服务器-hub0060" aria-label="Permalink to &quot;隧道服务器（hub0060）&quot;">​</a></h1><p>在 <strong>FRP 类隧道路由</strong> 场景下，集中维护隧道服务端配置（控制端口、管理面板、HTTP/HTTPS 虚拟主机、客户端上限、Token/TLS、心跳等），查看汇总统计与运行态的 <strong>已注册客户端</strong>、<strong>已注册服务</strong>。同一页面通过左侧标签切换三个子视图。</p><p><img src="'+g+'" alt="隧道服务器管理：筛选、统计与列表"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>隧道服务器管理</strong></td><td>条件查询、统计卡片、分页列表；支持新增/编辑/查看配置弹窗，以及启动、停止、重启与删除（均会二次确认）。</td></tr><tr><td><strong>客户端注册列表</strong></td><td>展示当前已连接到隧道服务端的客户端运行时信息；列头支持输入过滤；右键可刷新列表。</td></tr><tr><td><strong>服务注册列表</strong></td><td>展示客户端已注册的代理服务（本地地址与远程端口等）；列头支持输入过滤；右键可刷新列表。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>隧道管理</strong> → <strong>隧道服务器</strong>。</p><hr><h2 id="页面结构-左侧标签" tabindex="-1">页面结构（左侧标签） <a class="header-anchor" href="#页面结构-左侧标签" aria-label="Permalink to &quot;页面结构（左侧标签）&quot;">​</a></h2><ol><li><strong>隧道服务器管理</strong>：配置型数据，带统计与工具栏。</li><li><strong>客户端注册列表</strong>：运行时客户端列表。</li><li><strong>服务注册列表</strong>：运行时服务列表。</li></ol><p>当前实现中，客户端与服务列表的「按某台服务器过滤」依赖传入的服务器 ID；父页面若未下发该参数，则接口以 <strong>空参数</strong> 拉取 <strong>全部服务器</strong> 下的注册数据（与代码中 <code>tunnelServerId || &#39;&#39;</code> 一致）。</p><hr><h2 id="隧道服务器管理" tabindex="-1">隧道服务器管理 <a class="header-anchor" href="#隧道服务器管理" aria-label="Permalink to &quot;隧道服务器管理&quot;">​</a></h2><h3 id="加载与统计" tabindex="-1">加载与统计 <a class="header-anchor" href="#加载与统计" aria-label="Permalink to &quot;加载与统计&quot;">​</a></h3><ul><li><strong>列表数据</strong>：进入本标签后，需点击 <strong>查询</strong> 才会按当前筛选条件请求列表（页面挂载时仅会拉取顶部 <strong>统计</strong> 数据）。</li><li><strong>统计卡片</strong>：展示总服务器数、运行中、已停止、错误状态；下方为 <strong>客户端统计</strong>（总客户端数 + 使用率进度条）与 <strong>连接统计</strong>（总连接数 + 负载进度条）。使用率/负载百分比由前端按固定上限换算展示，用于直观参考。</li></ul><h3 id="筛选项" tabindex="-1">筛选项 <a class="header-anchor" href="#筛选项" aria-label="Permalink to &quot;筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务器名称</strong></td><td>占位：请输入服务器名称。</td></tr><tr><td><strong>服务器状态</strong></td><td>全部 / <strong>运行中</strong> / <strong>已停止</strong> / <strong>错误</strong>。</td></tr><tr><td><strong>控制地址</strong></td><td>占位：请输入控制地址（可与列表中「IP:控制端口」展示对照）。</td></tr><tr><td><strong>活动状态</strong></td><td>全部 / <strong>活动</strong> / <strong>非活动</strong>。</td></tr></tbody></table><p><strong>查询</strong> 按条件刷新列表并回到分页第一页逻辑由搜索表单与分页联动处理。<strong>重置</strong> 清空条件后再次查询。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增服务器</strong></td><td>打开多 Tab 表单弹窗，填写后保存创建。</td></tr><tr><td><strong>编辑</strong></td><td>取 <strong>已勾选行</strong>；若无勾选，则取 <strong>当前高亮（点击）行</strong>。未选中任何目标时提示先选择。编辑前会再请求一次详情以保证数据最新。</td></tr><tr><td><strong>删除</strong></td><td>与 <strong>编辑</strong> 相同的选中规则，但仅处理 <strong>一条</strong> 记录：确认后删除该隧道服务器（非多选批量删除）。</td></tr><tr><td><strong>查询</strong> / <strong>重置</strong></td><td>与筛表单联动。</td></tr></tbody></table><h3 id="表格列-主要" tabindex="-1">表格列（主要） <a class="header-anchor" href="#表格列-主要" aria-label="Permalink to &quot;表格列（主要）&quot;">​</a></h3><p>含左侧 <strong>勾选</strong> 与 <strong>序号</strong>。数据列包括：<strong>服务器名称</strong>（可排序；运行中名称高亮样式）、<strong>控制地址</strong>（由控制 IP 与控制端口拼接）、<strong>管理端口</strong>、<strong>状态</strong>（运行中 / 已停止 / 错误 / 未知）、<strong>HTTP 端口</strong>、<strong>HTTPS 端口</strong>、<strong>最大客户端</strong>、<strong>Token 认证</strong>（启用/禁用标签）、<strong>TLS</strong>（启用/禁用）、<strong>心跳间隔(秒)</strong>、<strong>心跳超时(秒)</strong>、<strong>启动时间</strong>、<strong>创建时间</strong>、<strong>创建人</strong>、<strong>活动状态</strong> 等；底部分页。</p><h3 id="新增-编辑-查看" tabindex="-1">新增 / 编辑 / 查看 <a class="header-anchor" href="#新增-编辑-查看" aria-label="Permalink to &quot;新增 / 编辑 / 查看&quot;">​</a></h3><p>使用同一弹窗组件，标题随模式变化，例如 <strong>新增隧道服务器</strong>、<strong>编辑隧道服务器</strong>、<strong>查看隧道服务器详情</strong>。表单分为 <strong>基础配置</strong>、<strong>网络配置</strong>、<strong>安全配置</strong>、<strong>高级配置</strong>、<strong>其他信息</strong> 等 Tab，涵盖控制地址与端口、管理面板端口、HTTP/HTTPS 端口、最大客户端数、每客户端端口上限、允许端口范围、Token/TLS 及证书路径、心跳与日志级别、备注与活动状态等；查看模式下字段为只读，确认不会提交写操作。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+a+'" alt="隧道服务器表格右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据</strong> / <strong>复制单元格</strong></td><td>表格内置，便于复制配置信息。</td></tr><tr><td><strong>查看详情</strong></td><td>只读打开上述表单弹窗。</td></tr><tr><td><strong>编辑</strong></td><td>拉取最新详情后进入编辑弹窗。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行对应服务器，需确认。</td></tr><tr><td><strong>启动服务器</strong></td><td>确认后调用启动接口，成功后刷新列表。</td></tr><tr><td><strong>停止服务器</strong></td><td>确认后停止（提示将断开客户端连接），成功后刷新列表。</td></tr><tr><td><strong>重启服务器</strong></td><td>确认后重启，成功后刷新列表。</td></tr></tbody></table><hr><h2 id="客户端注册列表" tabindex="-1">客户端注册列表 <a class="header-anchor" href="#客户端注册列表" aria-label="Permalink to &quot;客户端注册列表&quot;">​</a></h2><p>展示已注册客户端：<strong>服务器 ID</strong>、<strong>客户端 ID</strong>、<strong>客户端名称</strong>、<strong>服务器地址</strong>（地址与端口拼接）、<strong>客户端 IP</strong>、<strong>客户端 MAC</strong>、<strong>客户端版本</strong>、<strong>操作系统</strong>、<strong>连接状态</strong>（已连接 / 已断开 / 连接中 / 错误 等映射文案）、<strong>服务数量</strong>、<strong>认证状态</strong>、<strong>最后心跳</strong> 等。多列带表头 <strong>筛选图标</strong>，可在列头输入关键字过滤。</p><p><img src="'+e+'" alt="客户端注册列表与右键菜单"></p><p><strong>右键</strong>：复制行数据、复制单元格、<strong>刷新</strong>（重新请求列表）。</p><hr><h2 id="服务注册列表" tabindex="-1">服务注册列表 <a class="header-anchor" href="#服务注册列表" aria-label="Permalink to &quot;服务注册列表&quot;">​</a></h2><p>展示已注册服务：<strong>服务器 ID</strong>、<strong>客户端 ID</strong>、<strong>服务 ID</strong>、<strong>服务名称</strong>、<strong>服务类型</strong>（如 tcp）、<strong>本地地址</strong>（本地 IP 与本地端口拼接）、<strong>远程端口</strong>、<strong>服务状态</strong>、<strong>连接数</strong>、<strong>总连接数</strong>、<strong>注册时间</strong>、<strong>最后活动时间</strong> 等；其中 ID 与名称列支持表头输入过滤。</p><p><img src="'+d+'" alt="服务注册列表"></p><p><strong>右键</strong>：复制行数据、复制单元格、<strong>刷新</strong>（重新请求列表）。</p><hr><h2 id="与隧道客户端-hub0062-的关系" tabindex="-1">与隧道客户端（hub0062）的关系 <a class="header-anchor" href="#与隧道客户端-hub0062-的关系" aria-label="Permalink to &quot;与隧道客户端（hub0062）的关系&quot;">​</a></h2><p><strong>hub0060</strong> 侧重 <strong>隧道服务端（frps 类）</strong> 的配置与运行态监控；<strong>隧道客户端（frpc 类）</strong> 则 <strong>单独部署</strong> 在内网或业务侧主机上，在 <strong><a href="./hub0062.html">隧道客户端（hub0062）</a></strong> 中维护其连接参数与「隧道服务」条目，向本页所配置的 <strong>控制地址/端口</strong> 发起长连，并把 <strong>本机本地端口上的业务</strong> 暴露到隧道服务端对外监听地址上。</p><p>整体穿透关系可参考同一张 <strong><a href="../images/tunnel_architecture.svg">架构原理图</a></strong>（hub0062 文档中亦引用）。实际是否已连接、已注册多少客户端/服务，以本模块 <strong>客户端注册列表</strong>、<strong>服务注册列表</strong> 与服务器运行状态为准。</p>',43)])])}const P=r(h,[["render",l]]);export{_ as __pageData,P as default};
